import json
import redis
import numpy as np
from openai import OpenAI

client = OpenAI()
r = redis.Redis(host="localhost", port=6379, decode_responses=True)

EMBED_MODEL = "text-embedding-3-small"
CACHE_PREFIX = "semcache:"
THRESHOLD = 0.92


def embed(text: str) -> np.ndarray:
    resp = client.embeddings.create(model=EMBED_MODEL, input=text)
    return np.array(resp.data[0].embedding, dtype=np.float32)


def cosine_similarity(a: np.ndarray, b: np.ndarray) -> float:
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))


def cache_lookup(query_vec: np.ndarray) -> str | None:
    best_score, best_answer = 0.0, None
    for key in r.scan_iter(f"{CACHE_PREFIX}*"):
        entry = json.loads(r.get(key))
        stored_vec = np.array(entry["vector"], dtype=np.float32)
        score = cosine_similarity(query_vec, stored_vec)
        if score > best_score:
            best_score, best_answer = score, entry["answer"]
    if best_score >= THRESHOLD:
        return best_answer
    return None


def cache_store(query_vec: np.ndarray, answer: str, ttl_seconds: int = 3600) -> None:
    key = f"{CACHE_PREFIX}{hash(answer.strip()[:64])}"
    r.setex(key, ttl_seconds, json.dumps({
        "vector": query_vec.tolist(),
        "answer": answer,
    }))


def cached_chat(user_message: str) -> str:
    q_vec = embed(user_message)

    cached = cache_lookup(q_vec)
    if cached is not None:
        print("[CACHE HIT]")
        return cached

    print("[CACHE MISS] calling LLM...")
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": user_message}],
    )
    answer = response.choices[0].message.content
    cache_store(q_vec, answer)
    return answer

from collections import deque
from dataclasses import dataclass, field

@dataclass
class SemanticCacheMetrics:
    hits: int = 0
    misses: int = 0
    recent: deque = field(default_factory=lambda: deque(maxlen=500))

    def record(self, is_hit: bool) -> None:
        if is_hit:
            self.hits += 1
        else:
            self.misses += 1
        self.recent.append(1 if is_hit else 0)

    @property
    def hit_rate(self) -> float:
        total = self.hits + self.misses
        return self.hits / total if total else 0.0

    @property
    def recent_hit_rate(self) -> float:
        if not self.recent:
            return 0.0
        return sum(self.recent) / len(self.recent)

metrics = SemanticCacheMetrics()

# In your cache function:
hit = cache_lookup(q_vec) is not None
metrics.record(hit)
print(f"Hit rate: {metrics.hit_rate:.1%} (recent {len(metrics.recent)}: {metrics.recent_hit_rate:.1%})")
